import unittest, numpy as np

class TestKalmanPairsPipeline(unittest.TestCase):
    """Kalman + Pairs Trading entegrasyon testi."""
    def test_kalman_feeds_pairs(self):
        from modules.kalman_filter_engine import get_kalman_engine
        from modules.pairs_trading_engine import get_pairs_trading_engine
        kalman = get_kalman_engine()
        pairs  = get_pairs_trading_engine()
        prices_x = [100 + i*0.1 + np.random.normal(0,0.5) for i in range(100)]
        prices_y = [2*x + 5 + np.random.normal(0,1) for x in prices_x]
        filtered = kalman.filter_price_series(prices_x)
        signal   = pairs.generate_live_signal(prices_y[-1], filtered["filtered_prices"][-1], 2.0)
        self.assertIn(signal["signal"], ["LONG_SPREAD","SHORT_SPREAD","HOLD","EXIT"])

class TestFactorFixedIncomePipeline(unittest.TestCase):
    """Factor Model + Fixed Income birlikte çalışma testi."""
    def test_macro_informs_fi(self):
        from modules.macro_regime_engine import get_macro_regime_engine
        from modules.fixed_income_engine import get_fixed_income_engine
        macro = get_macro_regime_engine()
        fi    = get_fixed_income_engine()
        outlook = macro.generate_macro_report(2.5,3.0,4.0,4.5,52.0,4.2,4.0,18.0)
        curve   = fi.get_yield_curve()
        self.assertIn("yields", curve)
        self.assertIsNotNone(outlook["regime"])

